//! Direct coverage for `from_r/references.rs` — borrowed-view conversions.
//!
//! Regression target: #759. The `&T` / `&mut T` single-element borrowed-scalar
//! impls in `miniextendr-api/src/from_r/references.rs` (generated by
//! `impl_ref_conversions_for!` for every `RNativeType`: `i32`, `f64`, `u8`,
//! `RLogical`, `Rcomplex`) were at 0% region coverage — only exercised
//! indirectly when the proc-macro called into them. These tests construct R
//! SEXPs directly and drive both the checked (`try_from_sexp`) and unchecked
//! (`try_from_sexp_unchecked`) entry points, asserting the exact error variants
//! on the type-mismatch and length-mismatch branches.
//!
//! Scope split (per #759): the `&[T]` slice blanket lives in the `from_r.rs`
//! root and is already covered by `tests/from_r.rs`. Here we target the
//! single-element borrowed scalar variants. The literal `&str` / `String`
//! single-element impls live in `from_r/strings.rs` (not `references.rs`); we
//! cover their under-tested error + unchecked branches alongside, since the
//! issue lists them.

mod r_test_utils;

use miniextendr_api::RLogical;
use miniextendr_api::from_r::{SexpError, TryFromSexp};
use miniextendr_api::prelude::{SEXP, SexpExt};
use miniextendr_api::sys::Rf_allocVector;
use miniextendr_api::{R_xlen_t, SEXPTYPE};

#[derive(Default)]
struct ProtectCount(i32);

impl ProtectCount {
    unsafe fn protect(&mut self, sexp: SEXP) -> SEXP {
        unsafe { miniextendr_api::sys::Rf_protect(sexp) };
        self.0 += 1;
        sexp
    }
}

impl Drop for ProtectCount {
    fn drop(&mut self) {
        if self.0 > 0 {
            unsafe { miniextendr_api::sys::Rf_unprotect(self.0) };
        }
    }
}

unsafe fn make_int_vec(values: &[i32], guard: &mut ProtectCount) -> SEXP {
    let len = values.len() as R_xlen_t;
    let sexp = unsafe { guard.protect(Rf_allocVector(SEXPTYPE::INTSXP, len)) };
    let slice: &mut [i32] = unsafe { sexp.as_mut_slice() };
    slice.copy_from_slice(values);
    sexp
}

unsafe fn make_str_vec(values: &[&str], guard: &mut ProtectCount) -> SEXP {
    let len = values.len() as R_xlen_t;
    let sexp = unsafe { guard.protect(Rf_allocVector(SEXPTYPE::STRSXP, len)) };
    for (i, value) in values.iter().enumerate() {
        sexp.set_string_elt(i as R_xlen_t, SEXP::charsxp(value));
    }
    sexp
}

// region: references.rs — &T / &mut T single-element borrowed scalars

#[test]
fn references_borrowed_scalar_suite() {
    r_test_utils::with_r_thread(|| {
        ref_scalar_ok();
        ref_scalar_type_mismatch();
        ref_scalar_length_mismatch();
        ref_mut_scalar_ok_and_writes_through();
        ref_mut_scalar_type_mismatch();
        ref_scalar_unchecked();
    });
}

/// `&i32` / `&f64` / `&RLogical` from a single-element scalar SEXP: the happy
/// path through `impl_ref_conversions_for!`'s `&'static $t` checked branch.
fn ref_scalar_ok() {
    let mut guard = ProtectCount::default();
    unsafe {
        let int_sexp = guard.protect(SEXP::scalar_integer(7));
        let real_sexp = guard.protect(SEXP::scalar_real(2.5));
        let log_sexp = guard.protect(SEXP::scalar_logical(true));

        let int_ref: &'static i32 = TryFromSexp::try_from_sexp(int_sexp).unwrap();
        let real_ref: &'static f64 = TryFromSexp::try_from_sexp(real_sexp).unwrap();
        let log_ref: &'static RLogical = TryFromSexp::try_from_sexp(log_sexp).unwrap();

        assert_eq!(*int_ref, 7);
        assert_eq!(*real_ref, 2.5);
        assert_eq!(*log_ref, RLogical::TRUE);
    }
}

/// Wrong SEXPTYPE → `SexpError::Type` (the `SexpTypeError` branch in
/// `references.rs`). `&i32` from a REALSXP and `&f64` from an INTSXP.
fn ref_scalar_type_mismatch() {
    let mut guard = ProtectCount::default();
    unsafe {
        let real_sexp = guard.protect(SEXP::scalar_real(1.0));
        let int_sexp = guard.protect(SEXP::scalar_integer(1));

        let err = <&'static i32 as TryFromSexp>::try_from_sexp(real_sexp).unwrap_err();
        assert!(
            matches!(err, SexpError::Type(_)),
            "&i32 from REALSXP: {err:?}"
        );

        let err = <&'static f64 as TryFromSexp>::try_from_sexp(int_sexp).unwrap_err();
        assert!(
            matches!(err, SexpError::Type(_)),
            "&f64 from INTSXP: {err:?}"
        );
    }
}

/// Multi-element (and empty) vector → `SexpError::Length` (the
/// `SexpLengthError` branch in `references.rs`).
fn ref_scalar_length_mismatch() {
    let mut guard = ProtectCount::default();
    unsafe {
        let multi = make_int_vec(&[1, 2, 3], &mut guard);
        let empty = guard.protect(Rf_allocVector(SEXPTYPE::INTSXP, 0));

        let err = <&'static i32 as TryFromSexp>::try_from_sexp(multi).unwrap_err();
        assert!(
            matches!(err, SexpError::Length(_)),
            "&i32 from len-3: {err:?}"
        );

        let err = <&'static i32 as TryFromSexp>::try_from_sexp(empty).unwrap_err();
        assert!(
            matches!(err, SexpError::Length(_)),
            "&i32 from len-0: {err:?}"
        );
    }
}

/// `&mut i32` borrowed view: R observes writes through the returned reference.
fn ref_mut_scalar_ok_and_writes_through() {
    let mut guard = ProtectCount::default();
    unsafe {
        let int_sexp = guard.protect(SEXP::scalar_integer(10));

        let int_mut: &'static mut i32 = TryFromSexp::try_from_sexp(int_sexp).unwrap();
        *int_mut = 99;

        // Read it back through a fresh borrow — the write hit R-owned storage.
        let int_ref: &'static i32 = TryFromSexp::try_from_sexp(int_sexp).unwrap();
        assert_eq!(*int_ref, 99);
    }
}

/// `&mut T` type-mismatch branch in `references.rs`.
fn ref_mut_scalar_type_mismatch() {
    let mut guard = ProtectCount::default();
    unsafe {
        let real_sexp = guard.protect(SEXP::scalar_real(1.0));
        let err = <&'static mut i32 as TryFromSexp>::try_from_sexp(real_sexp).unwrap_err();
        assert!(
            matches!(err, SexpError::Type(_)),
            "&mut i32 from REALSXP: {err:?}"
        );

        // and the &mut length branch
        let multi = make_int_vec(&[1, 2], &mut guard);
        let err = <&'static mut i32 as TryFromSexp>::try_from_sexp(multi).unwrap_err();
        assert!(
            matches!(err, SexpError::Length(_)),
            "&mut i32 from len-2: {err:?}"
        );
    }
}

/// The `try_from_sexp_unchecked` branch of `references.rs` for `&i32` —
/// Ok on a valid scalar, plus its type/length error branches.
fn ref_scalar_unchecked() {
    let mut guard = ProtectCount::default();
    unsafe {
        let int_sexp = guard.protect(SEXP::scalar_integer(42));
        let int_ref: &'static i32 = TryFromSexp::try_from_sexp_unchecked(int_sexp).unwrap();
        assert_eq!(*int_ref, 42);

        let real_sexp = guard.protect(SEXP::scalar_real(1.0));
        let err = <&'static i32 as TryFromSexp>::try_from_sexp_unchecked(real_sexp).unwrap_err();
        assert!(
            matches!(err, SexpError::Type(_)),
            "unchecked &i32 from REALSXP: {err:?}"
        );

        let multi = make_int_vec(&[1, 2], &mut guard);
        let err = <&'static i32 as TryFromSexp>::try_from_sexp_unchecked(multi).unwrap_err();
        assert!(
            matches!(err, SexpError::Length(_)),
            "unchecked &i32 from len-2: {err:?}"
        );

        // &mut unchecked path too.
        let int_sexp2 = guard.protect(SEXP::scalar_integer(5));
        let int_mut: &'static mut i32 = TryFromSexp::try_from_sexp_unchecked(int_sexp2).unwrap();
        *int_mut = 6;
        let int_ref2: &'static i32 = TryFromSexp::try_from_sexp(int_sexp2).unwrap();
        assert_eq!(*int_ref2, 6);
    }
}
// endregion

// region: strings.rs — single-element &str / &[T] (issue-listed; under-covered branches)

#[test]
fn references_str_and_slice_suite() {
    r_test_utils::with_r_thread(|| {
        str_single_element_ok();
        str_multi_element_length_error();
        str_type_mismatch();
        str_and_slice_unchecked();
    });
}

/// `&str` from a single-element STRSXP — happy path (issue ask #1).
fn str_single_element_ok() {
    let mut guard = ProtectCount::default();
    unsafe {
        let str_sexp = make_str_vec(&["hello"], &mut guard);
        let as_str: &'static str = TryFromSexp::try_from_sexp(str_sexp).unwrap();
        assert_eq!(as_str, "hello");
    }
}

/// `&str` from a multi-element STRSXP → `SexpError::Length` (issue ask #2).
fn str_multi_element_length_error() {
    let mut guard = ProtectCount::default();
    unsafe {
        let str_sexp = make_str_vec(&["a", "b"], &mut guard);
        let err = <&'static str as TryFromSexp>::try_from_sexp(str_sexp).unwrap_err();
        assert!(
            matches!(err, SexpError::Length(_)),
            "&str from len-2: {err:?}"
        );
    }
}

/// `&str` from a non-STRSXP → `SexpError::Type` (issue ask #4 for the str path).
fn str_type_mismatch() {
    let mut guard = ProtectCount::default();
    unsafe {
        let int_sexp = guard.protect(SEXP::scalar_integer(1));
        let err = <&'static str as TryFromSexp>::try_from_sexp(int_sexp).unwrap_err();
        assert!(
            matches!(err, SexpError::Type(_)),
            "&str from INTSXP: {err:?}"
        );
    }
}

/// The `try_from_sexp_unchecked` path for `&str` and `&[T]` (issue ask #3).
fn str_and_slice_unchecked() {
    let mut guard = ProtectCount::default();
    unsafe {
        // &str unchecked (strings.rs)
        let str_sexp = make_str_vec(&["world"], &mut guard);
        let as_str: &'static str = TryFromSexp::try_from_sexp_unchecked(str_sexp).unwrap();
        assert_eq!(as_str, "world");

        // &str unchecked error branches
        let int_sexp = guard.protect(SEXP::scalar_integer(1));
        let err = <&'static str as TryFromSexp>::try_from_sexp_unchecked(int_sexp).unwrap_err();
        assert!(
            matches!(err, SexpError::Type(_)),
            "unchecked &str from INTSXP: {err:?}"
        );

        let multi_str = make_str_vec(&["a", "b"], &mut guard);
        let err = <&'static str as TryFromSexp>::try_from_sexp_unchecked(multi_str).unwrap_err();
        assert!(
            matches!(err, SexpError::Length(_)),
            "unchecked &str from len-2: {err:?}"
        );

        // &[T] unchecked (from_r.rs root blanket — issue ask #3)
        let int_vec = make_int_vec(&[4, 5, 6], &mut guard);
        let slice: &[i32] = TryFromSexp::try_from_sexp_unchecked(int_vec).unwrap();
        assert_eq!(slice, &[4, 5, 6]);
    }
}
// endregion
